INSERT INTO board (rqst_no, title, cont, rqst_id, ins_dt, upt_dt, views, group_no, parent_no, depth, order_no, secret, password, board_type)
SELECT #{rqstNo}
     , #{title}
     , #{cont}
     , #{rqstId}
     , NOW()
     , NOW()
     , 0
     , COALESCE(NULLIF(#{groupNo}, ''), P.group_no, #{rqstNo})
     , #{parentNo}
     , COALESCE(#{depth}, COALESCE(P.depth, -1) + 1)
     , #{orderNo}
     , COALESCE(#{secret}, 'N')
     , #{password}
     , 'SERMONS'
  FROM (SELECT 1) AS dummy
  LEFT JOIN board P ON P.rqst_no = #{parentNo}

mapper.update:
UPDATE board
   SET title = #{title}
     , cont = #{cont}
     , secret = COALESCE(#{secret}, 'N')
     , password = #{password}
     , upt_dt = NOW()
 WHERE rqst_no = #{rqstNo}

UPDATE board
   SET order_no = order_no + 1
 WHERE group_no = #{groupNo}
   AND order_no > #{orderNo}

UPDATE comment
   SET likes = likes + 1
 WHERE comment_id = #{commentId}

UPDATE comment
   SET likes = likes - 1
 WHERE comment_id = #{commentId}

UPDATE comment
   SET dislikes = dislikes + 1
 WHERE comment_id = #{commentId}

UPDATE comment
   SET dislikes = dislikes - 1
 WHERE comment_id = #{commentId}
